mapper.select:
SELECT r.user_id, u.username, u.real_name, u.student_no, COALESCE(c.class_name, '') AS class_name, r.score, e.total_score, e.pass_score, r.status, r.submit_time, r.duration, CASE WHEN r.score >= e.pass_score THEN 1 ELSE 0 END AS is_passed FROM t_exam_record r JOIN t_user u ON r.user_id = u.id LEFT JOIN t_class c ON u.class_id = c.id JOIN t_exam e ON r.exam_id = e.id WHERE r.exam_id = #{examId} AND r.status IN (1, 2) AND r.is_deleted = 0 AND u.is_deleted = 0
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.student_no LIKE CONCAT('%', #{keyword}, '%'))
AND u.class_id = #{classId}
ORDER BY r.score DESC, r.submit_time ASC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM t_exam_record r JOIN t_user u ON r.user_id = u.id WHERE r.exam_id = #{examId} AND r.status IN (1, 2) AND r.is_deleted = 0 AND u.is_deleted = 0
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.student_no LIKE CONCAT('%', #{keyword}, '%'))
AND u.class_id = #{classId}

SELECT ROW_NUMBER() OVER (ORDER BY r.score DESC, r.submit_time ASC) AS `rank`, r.user_id, u.real_name, u.student_no, r.score, r.status, r.submit_time FROM t_exam_record r JOIN t_user u ON r.user_id = u.id WHERE r.exam_id = #{examId} AND r.status IN (1, 2) AND r.is_deleted = 0 AND u.is_deleted = 0
AND u.class_id = #{classId}
ORDER BY r.score DESC, r.submit_time ASC

SELECT COUNT(*)
FROM t_exam_record r
JOIN t_user u ON r.user_id = u.id AND u.is_deleted = 0
WHERE r.exam_id = #{examId}
  AND r.status IN (1, 2)
  AND r.is_deleted = 0
  AND r.score >= #{min} AND r.score < #{max}

    AND u.class_id = #{classId}
